JavascriptExecutor js = (JavascriptExecutor) driver;
WebElement element = driver.findElement(By.id("hidden-btn"));

// 1. Click element (bypasses UI visibility checks)
js.executeScript("arguments[0].click();", element);

// 2. Scroll element into view
js.executeScript("arguments[0].scrollIntoView(true);", element);

// 3. Return a value to Java
String title = (String) js.executeScript("return document.title;");

// 4. Set a value directly
js.executeScript("arguments[0].value='test user';", driver.findElement(By.id("username")));
